// ─── ANALYTICS ───────────────────────────────────────────────────────────────
// Each session logs events to window.storage under a random session key.
// Admin view reads all sessions.
const SESSION_KEY = (() => {
  try {
    let k = sessionStorage.getItem("ih_session");
    if (!k) { k = "s_" + Math.random().toString(36).slice(2,10); sessionStorage.setItem("ih_session", k); }
    return k;
  } catch { return "s_" + Math.random().toString(36).slice(2,10); }
})();

async function logEvent(type, data = {}) {
  try {
    const existing = await window.storage.get(SESSION_KEY, true).catch(() => null);
    const session  = existing ? JSON.parse(existing.value) : { id: SESSION_KEY, events: [], started: Date.now() };
    session.events.push({ type, ts: Date.now(), ...data });
    await window.storage.set(SESSION_KEY, JSON.stringify(session), true);
  } catch {}
}

async function getAllSessions() {
  try {
    const keys = await window.storage.list("s_", true);
    const sessions = [];
    for (const key of (keys?.keys || [])) {
      try {
        const r = await window.storage.get(key, true);
        if (r?.value) sessions.push(JSON.parse(r.value));
      } catch {}
    }
    return sessions;
  } catch { return []; }
}

