// ─── COMPONENTS ──────────────────────────────────────────────────────────────
function TOTLogo({ height = 40 }) {
  return <img src={LOGO_SRC} alt="The Opportunity Trust" style={{ height, objectFit:"contain", display:"block" }} />;
}

function ImpactText({ text }) {
  // Bold the first sentence (up to first period after **)
  const parts = text.split("**");
  return (
    <p style={{ fontSize:"1rem", ...R, color:MUTED, lineHeight:1.7, margin:0 }}>
      {parts.map((p, i) => i % 2 === 1 ? <strong key={i} style={{ color:"#fff" }}>{p}</strong> : p)}
    </p>
  );
}

